    ${section('Sonstige Hinweise', otherWarnings.map(issueBlock).join(''))}

    <h2 style="font-size:18px;margin:28px 0 10px;">Nächste Schritte</h2>
    <ul style="margin:0;padding-left:20px;">
      ${nextSteps.map(step => `<li style="margin:6px 0;font-size:14px;line-height:1.35;">${esc(step)}</li>`).join('')}
    </ul>

    <div style="font-size:12px;color:#6b7280;margin-top:28px;border-top:1px solid #e5e7eb;padding-top:12px;">
      Automatisch erstellt durch n8n.
    </div>

  </div>
</div>
`;

const text = [
  `Automatenlager Check ${dateText}`,
  '',
  `MHD abgelaufen: ${mhdExpired.length}`,
  `MHD läuft bald ab: ${mhdSoon.length}`,
  `Niedriger Bestand: ${lowStock.length}`,
  `Daten-/Workflowfehler: ${dataIssues.length}`,
].join('\n');

return [{
  json: {
    email_subject: subject,
    email_body: html,
    email_text: text,
    alerts_count: alerts.length,
    mhd_expired_count: mhdExpired.length,
    mhd_soon_count: mhdSoon.length,
    low_stock_count: lowStock.length,
    data_issue_count: dataIssues.length,
    other_warning_count: otherWarnings.length
  }
}];

const rows = $input.all().map(i => i.json);

function clean(v) {
  return String(v ?? '')
    .replace(/\n/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function isResolved(v) {
  const s = clean(v).toUpperCase();
  return ['TRUE', 'JA', 'YES', '1', 'ERLEDIGT', 'RESOLVED'].includes(s);
}

function parseDate(v) {
  const raw = clean(v);
  if (!raw) return null;
  const d = new Date(raw);
  if (!Number.isNaN(d.getTime())) return d;
  return null;
}

function todayBerlinIso() {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Europe/Berlin',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  }).formatToParts(new Date());
  return [
    parts.find(p => p.type === 'year')?.value,
    parts.find(p => p.type === 'month')?.value,
    parts.find(p => p.type === 'day')?.value,
  ].join('-');
}

function isFromToday(row) {
  const raw = clean(row.created_at);
  if (!raw) return true;
  const d = parseDate(raw);
  if (!d) return true;
  const day = d.toLocaleDateString('en-CA', {
    timeZone: 'Europe/Berlin',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
  });
  return day === todayBerlinIso();
}

// Typen die frisch berechnet werden – nicht aus Fehler_und_Hinweise lesen
const SKIP_TYPES = new Set(['LOW_STOCK', 'MHD_WARNING', 'MHD_EXPIRED']);

const seen = new Set();

const alerts = rows
  .filter(row => !isResolved(row.resolved))
  .filter(row => isFromToday(row))
  .filter(row => !SKIP_TYPES.has(clean(row.type).toUpperCase()))
  .filter(row => {
    const key = `${clean(row.type)}|${clean(row.product_key)}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  })
  .map(row => ({
    created_at: clean(row.created_at),
    type: clean(row.type || 'OPEN_HINT'),
    severity: clean(row.severity || 'warning'),
    machine_id: clean(row.machine_id),
    product_key: clean(row.product_key),
    nayax_product_name: clean(row.nayax_product_name),
    internal_product_name: clean(row.internal_product_name),
    product_name: clean(row.product_name || row.nayax_product_name || row.internal_product_name || row.product_key),
    mdb_code: clean(row.mdb_code || row.actual_mdb_code || row.expected_mdb_code),
    message: clean(row.message),
    resolved: clean(row.resolved),
    change_id: clean(row.change_id),
    source: 'Fehler_und_Hinweise'
  }));

return [{
  json: {
    alerts,
    summary: {
      checked_hint_rows: rows.length,
      open_hints_today: alerts.length,
      created_at: new Date().toISOString()
    }
  }
}];
